diff --git a/llvm/lib/Analysis/IVDescriptors.cpp b/llvm/lib/Analysis/IVDescriptors.cpp
index f74ede4450ce..d4ba53855861 100644
--- a/llvm/lib/Analysis/IVDescriptors.cpp
+++ b/llvm/lib/Analysis/IVDescriptors.cpp
@@ -857,8 +857,21 @@ RecurrenceDescriptor::InstDesc RecurrenceDescriptor::isRecurrenceInstr(
   case Instruction::PHI:
     return InstDesc(I, Prev.getRecKind(), Prev.getExactFPMathInst());
   case Instruction::Sub:
-  case Instruction::Add:
-    return InstDesc(Kind == RecurKind::Add, I);
+  case Instruction::Add: {
+    if (Kind != RecurKind::Add)
+      return InstDesc(false, I);
+    // Check if this is an identity operation.
+    if (I->getOpcode() == Instruction::Add) {
+      // For Add: adding 0 is identity.
+      if (match(I->getOperand(0), m_Zero()) || match(I->getOperand(1), m_Zero()))
+        return InstDesc(false, I);
+    } else { // Instruction::Sub
+      // For Sub: subtracting 0 is identity (sub x, 0, not sub 0, x).
+      if (match(I->getOperand(1), m_Zero()))
+        return InstDesc(false, I);
+    }
+    return InstDesc(true, I);
+  }
   case Instruction::Mul:
     return InstDesc(Kind == RecurKind::Mul, I);
   case Instruction::And:
